def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 2:
            base_penalty = ratio ** 4
            penalty = 0
            for k in range(1, 6):
                penalty += ((-1)**k) * (ratio ** (2*k + 1)) / (k * 3)
            priorities[i] = base_penalty + abs(penalty * np.log1p(ratio))
            if capacity % 2 == 0:
                priorities[i] *= 1.1
            else:
                priorities[i] *= 0.9
        elif 1 < ratio <= 2:
            penalty = 0
            for k in range(1, 4):
                penalty += (ratio ** (2*k)) / (k**2 + 1)
            priorities[i] = ratio ** 3 + penalty
            if item > capacity * 1.5:
                priorities[i] += penalty * 0.5
            if capacity > 10:
                priorities[i] *= 0.95
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 8):
                sign = 1 if j % 3 == 0 else -1
                term = sign * (ratio ** j) / (j + 1)
                score += term
            multiplier = 20 if ratio < 0.25 else 12 if ratio < 0.5 else 7 if ratio < 0.75 else 4
            priorities[i] = abs(score) * multiplier
            if 0.7 < ratio < 1:
                extra = 0
                for m in range(1, 5):
                    extra += ((-1)**m) * (ratio ** m) / (m + 2)
                priorities[i] += abs(extra)
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        for divisor in range(2, 5):
            if capacity % divisor == 0 and priorities[i] != np.inf:
                adjustment = ((ratio + 1) / divisor) ** divisor
                if divisor % 2 == 0:
                    priorities[i] /= adjustment
                else:
                    priorities[i] *= adjustment
        if priorities[i] != np.inf and capacity > 5:
            decay = np.exp(-capacity / 20)
            priorities[i] *= decay
        if np.isnan(priorities[i]) or np.isinf(priorities[i]) and priorities[i] != np.inf:
            priorities[i] = np.inf
    return priorities
